## Setting Up a Step Functions State Machine with Lambda, Retry Logic & Error Handling

### Basic State Machine Definition (Amazon States Language)

```json
{
  "Comment": "Lambda orchestration with retry and error handling",
  "StartAt": "InvokeLambda",
  "States": {
    "InvokeLambda": {
      "Type": "Task",
      "Resource": "arn:aws:lambda:us-east-1:123456789:function:MyFunction",
      "Retry": [
        {
          "ErrorEquals": ["Lambda.ServiceException", "Lambda.TooManyRequestsException"],
          "IntervalSeconds": 2,
          "MaxAttempts": 3,
          "BackoffRate": 2
        },
        {
          "ErrorEquals": ["States.TaskFailed"],
          "IntervalSeconds": 5,
          "MaxAttempts": 2,
          "BackoffRate": 1.5
        }
      ],
      "Catch": [
        {
          "ErrorEquals": ["CustomError"],
          "Next": "HandleCustomError",
          "ResultPath": "$.error"
        },
        {
          "ErrorEquals": ["States.ALL"],
          "Next": "HandleGenericError",
          "ResultPath": "$.error"
        }
      ],
      "Next": "SuccessState"
    },
    "HandleCustomError": {
      "Type": "Pass",
      "Result": "Handled custom error",
      "End": true
    },
    "HandleGenericError": {
      "Type": "Pass",
      "Result": "Handled generic error",
      "End": true
    },
    "SuccessState": {
      "Type": "Succeed"
    }
  }
}
```

